package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfappl.bijdrage.patronaal.pensioenpijler2;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBasisRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenPatronaalRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.service.ExtraSqlService.SimpelWeddebepaling;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LogTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.PercentageBasisVormer;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.enumtypes.Ritme;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.Months;

import java.math.BigDecimal;
import java.util.Collection;
import java.util.EnumSet;
import java.util.Set;

@Slf4j
public class PensioenPijler2BonusAncienniteitDmfappl {
    public static final int TIEN = 10;
    public static final int MAANDEN_IN_JAAR = 12;
    private static final BigDecimal PENS2B_ANC_BASIS_PERCENTAGE = new BigDecimal("0.01");
    private static final Set<Ritme> PENS2_ANC_RITMES = EnumSet.of(Ritme.GEBLOK_ANC, Ritme.JAARLIJKS, Ritme.MANDATARIS_KLASSE);

    private final ConstantManager constantManager;
    private final Opdracht opdracht;
    private final RekenTijd rekenTijd;
    private final RegulManager regulManager;
    private final PersoonsDataManager persoonsDataManager;
    private final LoonElementManager loonElementManager;

    public PensioenPijler2BonusAncienniteitDmfappl(ConstantManager constantManager, RekenContext opdrachtContext, Opdracht opdracht) {
        this.constantManager = constantManager;
        this.opdracht = opdracht;

        regulManager = opdrachtContext.getRegulManager();
        persoonsDataManager = opdrachtContext.getUnchecked(RekenChainKey.PERSOONSDATA_MANAGER_KEY);
        loonElementManager = opdrachtContext.getLoonElementManager();
        rekenTijd = opdrachtContext.getUnchecked(RekenChainKey.REKENTIJD_KEY);
    }

    public void berekenBijdrageBonusTweedePensioenpijlerAnncienniteitWhenNeeded() {
        boolean bonusPens2Ancienniteit = constantManager.getActualConstant(Konstanten.KST_BIJDRAGE_PENS2B_ANCIENNITEIT, rekenTijd).getBoolean();
        if (bonusPens2Ancienniteit) {
            berekenBijdrageBonusTweedePensioenpijlerAnncienniteit();
        }
    }

    private void berekenBijdrageBonusTweedePensioenpijlerAnncienniteit() {

        SimpelWeddebepaling weddebepaling = persoonsDataManager.getSimpelWeddebepaling(opdracht, rekenTijd.beginDatum);
        if (weddebepaling == null) {
            regulManager.doRegulException(opdracht, Regulkode.FOUT_ANC_ONBEPAALD);
            return;
        }
        Ritme ritme = getRitme(opdracht, weddebepaling);
        int maanden = getMaanden(weddebepaling, ritme);
        int jaren = maanden / MAANDEN_IN_JAAR;
        BigDecimal percentageBijdrage = new BigDecimal(Math.max(jaren - TIEN, 0));
        percentageBijdrage = percentageBijdrage.multiply(PENS2B_ANC_BASIS_PERCENTAGE);
        Collection<LoonElement> loonElementen = loonElementManager.getOpdrachtsElementen(opdracht);

        MoneyKey basisKey = RekenBasisRszKey.BASIS_BONUS_TWEEDE_PENSIOENPIJLER_KEY;
        MoneyKey bijdrageKey = RekenPatronaalRszKey.PATRONALE_BIJDRAGE_BONUS_TWEEDE_PENSIOENPIJLER_KEY;
        String bijdrageNaam = "PENS2B_ANCIENNITEIT";
        Money basisSocialeBijdrage = RekenTools.getSomProperty(basisKey, loonElementen);

        log.debug("{} opdrachtid: {} {} = {}", bijdrageNaam, opdracht.getId(), basisKey, basisSocialeBijdrage);
        if (basisSocialeBijdrage.signum() != 0) {
            Money bijdrage = basisSocialeBijdrage.multiply(percentageBijdrage);
            log.debug("percentage={},{} = {}", percentageBijdrage, bijdrageNaam, bijdrage);
            PercentageBasisVormer.vormBedragAlsPercentageBasisAdd(bijdrageKey, basisKey, percentageBijdrage, loonElementen);
            log.debug("{};basisKey \"{}\":{};bijdrageKey \"{}\":{}", LogTools.toSimpleLog(opdracht), basisKey, basisSocialeBijdrage, bijdrageNaam, bijdrage);
        }
    }

    private Ritme getRitme(Opdracht opdracht, SimpelWeddebepaling weddebepaling) {
        Ritme ritme = weddebepaling.getGeldelijkeAncienniteitRitme();
        if (!PENS2_ANC_RITMES.contains(ritme)) {
            regulManager.doRegulException(opdracht, Regulkode.FOUT_ANC_ONBEPAALD);
        }
        return ritme;
    }

    private int getMaanden(SimpelWeddebepaling weddebepaling, Ritme ritme) {
        int maanden = weddebepaling.getGeldelijkeAncienniteitMaanden();
        if (ritme == Ritme.JAARLIJKS) {
            maanden += Months.monthsBetween(weddebepaling.getGeldelijkeAncienniteitDatum(), rekenTijd.beginDatum).getMonths();
        }
        return maanden;
    }
}
